// Embedded fonts for credential rendering (certificate + wallet card).
//
// Latin woff2 subsets, base64-inlined so worker renders are deterministic and
// pixel-identical in every environment (dev Mac, CI, Dokploy container) with
// no network fetch and no asset-copy step in the worker bundle.
//
// Cormorant Garamond (variable, wght 300-700 + italic) — engraved serif for
// certificate headings/body. Great Vibes — calligraphic script for recipient
// names. Archivo (variable) — geometric sans for the wallet card.
// Source: Google Fonts (OFL licensed), latin subsets.

const CORMORANT_B64 =
  ''

const CORMORANT_ITALIC_B64 =
  ''

const GREAT_VIBES_B64 =
  ''

const ARCHIVO_B64 =
  ''

// One @font-face block per file; the variable files cover the full weight
// range so a single declaration serves every weight the templates use.
export const credentialFontFaces = `
@font-face {
  font-family: 'Cormorant Garamond';
  font-style: normal;
  font-weight: 300 700;
  src: url(data:font/woff2;base64,${CORMORANT_B64}) format('woff2');
}
@font-face {
  font-family: 'Cormorant Garamond';
  font-style: italic;
  font-weight: 300 700;
  src: url(data:font/woff2;base64,${CORMORANT_ITALIC_B64}) format('woff2');
}
@font-face {
  font-family: 'Great Vibes';
  font-style: normal;
  font-weight: 400;
  src: url(data:font/woff2;base64,${GREAT_VIBES_B64}) format('woff2');
}
@font-face {
  font-family: 'Archivo';
  font-style: normal;
  font-weight: 100 900;
  src: url(data:font/woff2;base64,${ARCHIVO_B64}) format('woff2');
}
`
